/**
 * Inline data URL of the bundled scientist PNG. Generated by base64
 * encoding `scientist.png` once (the PNG itself stays in this dir as
 * the source of truth — regenerate this constant via
 * `base64 -w 0 scientist.png` if the asset ever changes).
 *
 * Used by `BUILT_IN_SCIENTIST_SPRITESET.image.path` so the engine can
 * load the starter character without any file-resolution path. Works
 * identically across GJS (where `file://` paths require absolute
 * resolution) and the browser.
 */
export const SCIENTIST_PNG_DATA_URL =
  'data:image/png;base64,'
